SELECT m.id, m.role_group_id, rg.group_name AS role_group_name, m.role_id, r.role_name AS role_name, m.created_at, m.updated_at FROM role_group_role_mapping m LEFT JOIN role_group_management rg ON m.role_group_id = rg.id LEFT JOIN role_management r ON m.role_id = r.id
ORDER BY ${params.sortField} ${params.sortDirection}
LIMIT #{params.offset}, #{params.limit}
